                  <Label htmlFor="ownerPhone">대표자 연락처</Label>
                  <Input
                    id="ownerPhone"
                    type="tel"
                    placeholder="010-1234-5678"
                    value={academyFormData.ownerPhone}
                    onChange={(e) => handleAcademyInputChange('ownerPhone', e.target.value)}
                    required
                    data-testid="input-owner-phone"
