                <div className="space-y-2">
                  <Label htmlFor="adminName">관리자명</Label>
                  <Input
                    id="adminName"
                    type="text"
                    placeholder="시스템 관리자 성함"
                    value={academyFormData.name}
                    onChange={(e) => handleAcademyInputChange('name', e.target.value)}
                    required
                    data-testid="input-admin-name"
