                <div className="space-y-2">
                  <Label htmlFor="teacherName">교사 이름</Label>
                  <Input
                    id="teacherName"
                    type="text"
                    placeholder="교사 성함"
                    value={teacherFormData.name}
                    onChange={(e) => handleTeacherInputChange('name', e.target.value)}
                    required
                    data-testid="input-teacher-name"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="teacherEmail">교사 이메일</Label>
                  <Input
                    id="teacherEmail"
                    type="email"
                    placeholder="teacher@academy.com"
                    value={teacherFormData.email}
                    onChange={(e) => handleTeacherInputChange('email', e.target.value)}
                    required
                    data-testid="input-teacher-email"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="teacherPassword">비밀번호</Label>
                  <Input
                    id="teacherPassword"
                    type="password"
                    placeholder="6자 이상 입력하세요"
                    value={teacherFormData.password}
                    onChange={(e) => handleTeacherInputChange('password', e.target.value)}
                    required
                    minLength={6}
                    data-testid="input-teacher-password"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="subject">담당 과목</Label>
                  <Input
                    id="subject"
                    type="text"
                    placeholder="예: 수학, 영어, 국어"
                    value={teacherFormData.subject}
                    onChange={(e) => handleTeacherInputChange('subject', e.target.value)}
                    required
                    data-testid="input-subject"
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="teacherPhone">연락처 (선택)</Label>
                  <Input
                    id="teacherPhone"
                    type="tel"
                    placeholder="010-1234-5678"
                    value={teacherFormData.phone}
                    onChange={(e) => handleTeacherInputChange('phone', e.target.value)}
                    data-testid="input-teacher-phone"
                  />
                </div>
              </>
            )}

            <Button 
              type="submit" 
              className="w-full" 
              disabled={isLoading}
              data-testid="button-submit-signup"
            >
              {isLoading ? (
                signupType === 'academy' ? "학원 등록 중..." : "교사 가입 중..."
              ) : (
                <>
                  <UserPlus className="h-4 w-4 mr-2" />
                  {signupType === 'academy' ? '학원 등록하기' : '교사 가입하기'}
                </>
              )}
            </Button>
          </form>

          <div className="mt-4 text-center">
            <Button 
              variant="ghost" 
              onClick={onBackToLogin}
              className="w-full"
              data-testid="button-back-to-login"
            >
              <ArrowLeft className="h-4 w-4 mr-2" />
              로그인으로 돌아가기
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/SuperAdminDashboar.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Building2, Users, Check, Calendar } from "lucide-react";
import { queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

interface Tenant {
  id: string;
  accountNumber: string;
  name: string;
  ownerName: string;
  ownerPhone: string;
  status: 'pending' | 'active' | 'expired' | 'suspended';
  activeUntil: string | null;
  createdAt: string;
  updatedAt: string;
}

export default function SuperAdminDashboard() {
  const { toast } = useToast();

  // 모든 테넌트 조회
  const { data: tenants = [], isLoading } = useQuery<Tenant[]>({
    queryKey: ['/api/superadmin/tenants'],
  });

  // 테넌트 승인 mutation
  const approveMutation = useMutation({
    mutationFn: async (tenantId: string) => {
      const response = await fetch(`/api/superadmin/tenants/${tenantId}/approve`, {
        method: 'PUT',
        credentials: 'include',
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || '승인 중 오류가 발생했습니다.');
      }

      return response.json();
    },
    onSuccess: (data) => {
      toast({
        title: "승인 완료",
        description: `${data.tenant.name}이 승인되었습니다.`,
      });
      queryClient.invalidateQueries({ queryKey: ['/api/superadmin/tenants'] });
    },
    onError: (error: Error) => {
      toast({
        title: "승인 실패",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const getStatusBadgeVariant = (status: string) => {
    switch (status) {
      case 'pending': return 'outline';
      case 'active': return 'default';
      case 'expired': return 'secondary';
      case 'suspended': return 'destructive';
      default: return 'outline';
    }
  };

  const getStatusText = (status: string) => {
    switch (status) {
      case 'pending': return '승인 대기';
      case 'active': return '활성';
      case 'expired': return '만료';
      case 'suspended': return '정지';
      default: return status;
    }
  };

  const pendingTenants = tenants.filter(t => t.status === 'pending');
  const activeTenants = tenants.filter(t => t.status === 'active');

  if (isLoading) {
    return (
      <div className="p-6">
        <div className="flex items-center justify-center h-64">
          <div className="text-center">
            <div className="text-lg font-semibold">테넌트 정보 로딩 중...</div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex items-center gap-2">
        <Building2 className="h-6 w-6" />
        <h1 className="text-2xl font-bold">슈퍼관리자 대시보드</h1>
      </div>

      {/* 통계 카드 */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">승인 대기</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{pendingTenants.length}</div>
            <p className="text-xs text-muted-foreground">
              승인이 필요한 학원
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">활성 학원</CardTitle>
            <Check className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{activeTenants.length}</div>
            <p className="text-xs text-muted-foreground">
              운영 중인 학원
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">전체 학원</CardTitle>
            <Building2 className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{tenants.length}</div>
            <p className="text-xs text-muted-foreground">
              등록된 모든 학원
            </p>
          </CardContent>
        </Card>
      </div>

      {/* 승인 대기 목록 */}
      {pendingTenants.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle>승인 대기 학원</CardTitle>
            <CardDescription>
              다음 학원들이 승인을 기다리고 있습니다.
            </CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {pendingTenants.map((tenant) => (
                <div
                  key={tenant.id}
                  className="flex items-center justify-between p-4 border rounded-lg"
                  data-testid={`tenant-pending-${tenant.id}`}
                >
                  <div className="space-y-1">
                    <div className="font-medium">{tenant.name}</div>
                    <div className="text-sm text-muted-foreground">
                      대표자: {tenant.ownerName} | 연락처: {tenant.ownerPhone}
                    </div>
                    <div className="text-xs text-muted-foreground">
                      계정번호: {tenant.accountNumber} | 신청일: {new Date(tenant.createdAt).toLocaleDateString()}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    <Badge variant={getStatusBadgeVariant(tenant.status)}>
                      {getStatusText(tenant.status)}
                    </Badge>
                    <Button
                      size="sm"
                      onClick={() => approveMutation.mutate(tenant.id)}
                      disabled={approveMutation.isPending}
                      data-testid={`button-approve-${tenant.id}`}
                    >
                      {approveMutation.isPending ? '승인 중...' : '승인'}
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* 전체 학원 목록 */}
      <Card>
        <CardHeader>
          <CardTitle>전체 학원 목록</CardTitle>
          <CardDescription>
            시스템에 등록된 모든 학원을 확인할 수 있습니다.
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {tenants.map((tenant) => (
              <div
                key={tenant.id}
                className="flex items-center justify-between p-4 border rounded-lg"
                data-testid={`tenant-all-${tenant.id}`}
              >
                <div className="space-y-1">
                  <div className="font-medium">{tenant.name}</div>
                  <div className="text-sm text-muted-foreground">
                    대표자: {tenant.ownerName} | 연락처: {tenant.ownerPhone}
                  </div>
                  <div className="text-xs text-muted-foreground">
                    계정번호: {tenant.accountNumber} | 
                    {tenant.activeUntil && (
                      <span className="ml-1">
                        활성기간: {new Date(tenant.activeUntil).toLocaleDateString()}까지
                      </span>
                    )}
                  </div>
                </div>
                <Badge variant={getStatusBadgeVariant(tenant.status)}>
                  {getStatusText(tenant.status)}
                </Badge>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/Teachers.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Plus, Edit, Trash2, Users, Phone, Mail, BookOpen } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Teacher } from "@shared/schema";

const teacherFormSchema = z.object({
  userId: z.string().optional(),
  name: z.string().min(1, "이름을 입력해주세요"),
  subject: z.string().min(1, "담당 과목을 입력해주세요"),
  phone: z.string().optional(),
});

type TeacherFormData = z.infer<typeof teacherFormSchema>;

interface TeachersProps {
  userRole: 'owner' | 'teacher' | 'superadmin';
}

export default function Teachers({ userRole }: TeachersProps) {
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [editingTeacher, setEditingTeacher] = useState<Teacher | null>(null);
  const { toast } = useToast();

  // Fetch teachers
  const { data: teachers = [], isLoading } = useQuery<Teacher[]>({
    queryKey: ['/api/teachers'],
  });

  // Add teacher mutation
  const addTeacherMutation = useMutation({
    mutationFn: async (data: TeacherFormData) => {
      const response = await apiRequest('POST', '/api/teachers', data);
      return await response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/teachers'] });
      setIsAddDialogOpen(false);
      toast({
        title: "교사 등록 완료",
        description: "새 교사가 성공적으로 등록되었습니다.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "교사 등록 실패",
        description: error.message || "교사 등록 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  // Edit teacher mutation
  const editTeacherMutation = useMutation({
    mutationFn: async ({ id, data }: { id: string, data: TeacherFormData }) => {
      const response = await apiRequest('PUT', `/api/teachers/${id}`, data);
      return await response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/teachers'] });
      setIsEditDialogOpen(false);
      setEditingTeacher(null);
      toast({
        title: "교사 수정 완료",
        description: "교사 정보가 성공적으로 수정되었습니다.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "교사 수정 실패",
        description: error.message || "교사 수정 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  // Delete teacher mutation
  const deleteTeacherMutation = useMutation({
    mutationFn: async (id: string) => {
      await apiRequest('DELETE', `/api/teachers/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/teachers'] });
      toast({
        title: "교사 삭제 완료",
        description: "교사가 성공적으로 삭제되었습니다.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "교사 삭제 실패",
        description: error.message || "교사 삭제 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  // Form for adding teacher
  const addForm = useForm<TeacherFormData>({
    resolver: zodResolver(teacherFormSchema),
    defaultValues: {
      name: "",
      subject: "",
      phone: "",
    },
  });

  // Form for editing teacher
  const editForm = useForm<TeacherFormData>({
    resolver: zodResolver(teacherFormSchema),
    defaultValues: {
      name: "",
      subject: "",
      phone: "",
    },
  });

  const handleAddTeacher = (data: TeacherFormData) => {
    addTeacherMutation.mutate(data);
  };

  const handleEditTeacher = (data: TeacherFormData) => {
    if (editingTeacher) {
      editTeacherMutation.mutate({ id: editingTeacher.id, data });
    }
  };

  const handleDeleteTeacher = (id: string) => {
    deleteTeacherMutation.mutate(id);
  };

  const openEditDialog = (teacher: Teacher) => {
    setEditingTeacher(teacher);
    editForm.reset({
      name: teacher.name,
      subject: teacher.subject,
      phone: teacher.phone || "",
    });
    setIsEditDialogOpen(true);
  };

  if (isLoading) {
    return (
      <div className="space-y-6 p-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold">교사 관리</h1>
        </div>
        <div className="text-center py-8">
          <div className="text-muted-foreground">교사 목록을 불러오는 중...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6" data-testid="teachers-page">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">교사 관리</h1>
          <p className="text-muted-foreground">
            교사 {teachers.length}명이 등록되어 있습니다
          </p>
        </div>

        {(userRole === 'owner' || userRole === 'superadmin') && (
          <Dialog open={isAddDialogOpen} onOpenChange={setIsAddDialogOpen}>
            <DialogTrigger asChild>
              <Button data-testid="button-add-teacher">
                <Plus className="h-4 w-4 mr-2" />
                교사 추가
              </Button>
            </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>새 교사 등록</DialogTitle>
              <DialogDescription>
                새로운 교사 정보를 입력해주세요.
              </DialogDescription>
            </DialogHeader>
            <Form {...addForm}>
              <form onSubmit={addForm.handleSubmit(handleAddTeacher)} className="space-y-4">
                <FormField
                  control={addForm.control}
                  name="name"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>이름</FormLabel>
                      <FormControl>
                        <Input placeholder="교사 이름을 입력하세요" data-testid="input-teacher-name" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={addForm.control}
                  name="subject"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>담당 과목</FormLabel>
                      <FormControl>
                        <Input placeholder="담당 과목을 입력하세요" data-testid="input-teacher-subject" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <FormField
                  control={addForm.control}
                  name="phone"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>연락처 (선택사항)</FormLabel>
                      <FormControl>
                        <Input placeholder="연락처를 입력하세요" data-testid="input-teacher-phone" {...field} />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />
                <DialogFooter>
                  <Button 
                    type="submit" 
                    disabled={addTeacherMutation.isPending}
                    data-testid="button-submit-add-teacher"
                  >
                    {addTeacherMutation.isPending ? "등록 중..." : "등록"}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
        )}

        {userRole === 'teacher' && (
          <div className="text-sm text-muted-foreground bg-muted/50 px-3 py-2 rounded-lg">
            📝 교사 등록/수정/삭제는 학원장만 가능합니다
          </div>
        )}
      </div>

      {/* Teachers Grid */}
      {teachers.length === 0 ? (
        <div className="text-center py-12 border-2 border-dashed border-muted-foreground/25 rounded-lg">
          <Users className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
          <div className="text-lg font-medium">등록된 교사가 없습니다</div>
          <p className="text-muted-foreground mt-2">첫 번째 교사를 등록해보세요.</p>
        </div>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
          {teachers.map((teacher) => (
            <Card key={teacher.id} className="hover-elevate" data-testid={`teacher-card-${teacher.id}`}>
              <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-2">
                <div className="flex items-center gap-2">
                  <CardTitle className="text-lg">{teacher.name}</CardTitle>
                  <Badge 
                    variant={teacher.isActive ? "default" : "secondary"}
                    data-testid={`teacher-status-${teacher.id}`}
                  >
                    {teacher.isActive ? "활성" : "비활성"}
                  </Badge>
                </div>
                {(userRole === 'owner' || userRole === 'superadmin') && (
                  <div className="flex items-center gap-1">
                    <Button
                      size="icon"
                      variant="ghost"
                      onClick={() => openEditDialog(teacher)}
                      data-testid={`button-edit-teacher-${teacher.id}`}
                    >
                      <Edit className="h-4 w-4" />
                    </Button>
                    <AlertDialog>
                      <AlertDialogTrigger asChild>
                        <Button
                          size="icon"
                          variant="ghost"
                          data-testid={`button-delete-teacher-${teacher.id}`}
                        >
                          <Trash2 className="h-4 w-4 text-destructive" />
                        </Button>
                      </AlertDialogTrigger>
                      <AlertDialogContent>
                        <AlertDialogHeader>
                          <AlertDialogTitle>교사 삭제</AlertDialogTitle>
                          <AlertDialogDescription>
                            정말로 {teacher.name} 교사를 삭제하시겠습니까?
                            이 작업은 되돌릴 수 없습니다.
                          </AlertDialogDescription>
                        </AlertDialogHeader>
                        <AlertDialogFooter>
                          <AlertDialogCancel>취소</AlertDialogCancel>
                          <AlertDialogAction
                            onClick={() => handleDeleteTeacher(teacher.id)}
                            data-testid={`button-confirm-delete-teacher-${teacher.id}`}
                          >
                            삭제
                          </AlertDialogAction>
                        </AlertDialogFooter>
                      </AlertDialogContent>
                    </AlertDialog>
                  </div>
                )}
              </CardHeader>
              <CardContent className="space-y-2">
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <BookOpen className="h-4 w-4" />
                  <span>{teacher.subject}</span>
                </div>
                {teacher.phone && (
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <Phone className="h-4 w-4" />
                    <span>{teacher.phone}</span>
                  </div>
                )}
                <div className="text-xs text-muted-foreground">
                  등록일: {new Date(teacher.createdAt).toLocaleDateString()}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Edit Dialog */}
      <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>교사 정보 수정</DialogTitle>
            <DialogDescription>
              교사 정보를 수정해주세요.
            </DialogDescription>
          </DialogHeader>
          <Form {...editForm}>
            <form onSubmit={editForm.handleSubmit(handleEditTeacher)} className="space-y-4">
              <FormField
                control={editForm.control}
                name="name"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>이름</FormLabel>
                    <FormControl>
                      <Input placeholder="교사 이름을 입력하세요" data-testid="input-edit-teacher-name" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={editForm.control}
                name="subject"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>담당 과목</FormLabel>
                    <FormControl>
                      <Input placeholder="담당 과목을 입력하세요" data-testid="input-edit-teacher-subject" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <FormField
                control={editForm.control}
                name="phone"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>연락처 (선택사항)</FormLabel>
                    <FormControl>
                      <Input placeholder="연락처를 입력하세요" data-testid="input-edit-teacher-phone" {...field} />
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />
              <DialogFooter>
                <Button 
                  type="submit" 
                  disabled={editTeacherMutation.isPending}
                  data-testid="button-submit-edit-teacher"
                >
                  {editTeacherMutation.isPending ? "수정 중..." : "수정"}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

