import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { ChevronDown, ChevronRight, User, BookOpen, CheckCircle, XCircle, CreditCard, Calendar } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { Payment, Enrollment, Student, Class, Teacher } from "@shared/schema";

interface PaymentsProps {
  userRole: 'owner' | 'teacher' | 'superadmin';
}

interface StudentWithPaymentStatus {
  id: string;
  name: string;
  grade?: string | null;
  enrollment: Enrollment;
  latestPayment?: Payment;
  isPaid: boolean;
  tuition: number;
}

interface ClassWithStudents {
  id: string;
  name: string;
  students: StudentWithPaymentStatus[];
  schedule?: string;
}

interface TeacherWithClasses {
  id: string;
  name: string;
  subject: string;
  classes: ClassWithStudents[];
  totalStudents: number;
  paidStudents: number;
}

export default function Payments({ userRole }: PaymentsProps) {
  const [expandedTeachers, setExpandedTeachers] = useState<Set<string>>(new Set());
  const [expandedClasses, setExpandedClasses] = useState<Set<string>>(new Set());
  const [paymentDialog, setPaymentDialog] = useState<{
    isOpen: boolean;
    student?: StudentWithPaymentStatus;
    enrollment?: Enrollment;
  }>({ isOpen: false });
  const [paymentAmount, setPaymentAmount] = useState("");
  const [paymentDate, setPaymentDate] = useState(new Date().toISOString().slice(0, 10));

  const { toast } = useToast();

  // Fetch all required data
  const { data: teachers = [], isLoading: teachersLoading } = useQuery<Teacher[]>({
    queryKey: ['/api/teachers'],
  });

  const { data: classes = [], isLoading: classesLoading } = useQuery<Class[]>({
    queryKey: ['/api/classes'],
  });

  const { data: students = [], isLoading: studentsLoading } = useQuery<Student[]>({
    queryKey: ['/api/students'],
  });

  const { data: enrollments = [], isLoading: enrollmentsLoading } = useQuery<Enrollment[]>({
    queryKey: ['/api/enrollments'],
  });

  const { data: payments = [], isLoading: paymentsLoading } = useQuery<Payment[]>({
    queryKey: ['/api/payments'],
  });

  // Payment mutation
  const addPaymentMutation = useMutation({
    mutationFn: async (data: { enrollmentId: string; amount: number; paidDate: string }) => {
      const currentDate = new Date();
      const paymentMonth = `${currentDate.getFullYear()}-${String(currentDate.getMonth() + 1).padStart(2, '0')}`;

      const payload = {
        enrollmentId: data.enrollmentId,
        amount: data.amount,
        paymentMonth: paymentMonth,
        paidDate: new Date(data.paidDate).toISOString(),
        notes: "간편 납부",
      };

      const response = await apiRequest('POST', '/api/payments', payload);
      return await response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/payments'] });
      setPaymentDialog({ isOpen: false });
      setPaymentAmount("");
      toast({
        title: "납부 완료",
        description: "수납이 성공적으로 등록되었습니다.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "납부 실패",
        description: error.message || "납부 처리 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  // Process data to create teacher-class-student hierarchy
  const processTeacherData = (): TeacherWithClasses[] => {
    const teachersWithClasses: TeacherWithClasses[] = [];
    const currentMonth = new Date().toISOString().slice(0, 7); // YYYY-MM

    // Group classes by teacher
    teachers.forEach(teacher => {
      const teacherClasses = classes.filter(c => c.teacherId === teacher.id);
      const classesWithStudents: ClassWithStudents[] = [];

      teacherClasses.forEach(classItem => {
        const classEnrollments = enrollments.filter(e => e.classId === classItem.id && e.isActive);

        const studentsWithStatus: StudentWithPaymentStatus[] = classEnrollments.map(enrollment => {
          const student = students.find(s => s.id === enrollment.studentId);
          const latestPayment = payments.find(p => 
            p.enrollmentId === enrollment.id && 
            p.paymentMonth === currentMonth
          );

          return {
            id: student?.id || '',
            name: student?.name || '알 수 없음',
            grade: student?.grade,
            enrollment,
            latestPayment,
            isPaid: !!latestPayment,
            tuition: enrollment.tuition || classItem.defaultTuition || 0,
          };
        }).filter(s => s.id); // Filter out students without valid IDs

        if (studentsWithStatus.length > 0) {
          classesWithStudents.push({
            id: classItem.id,
            name: classItem.name,
            students: studentsWithStatus,
            schedule: classItem.schedule,
          });
        }
      });

      if (classesWithStudents.length > 0) {
        const totalStudents = classesWithStudents.reduce((sum, c) => sum + c.students.length, 0);
        const paidStudents = classesWithStudents.reduce((sum, c) => sum + c.students.filter(s => s.isPaid).length, 0);

        teachersWithClasses.push({
          id: teacher.id,
          name: teacher.name,
          subject: teacher.subject || '과목 미설정',
          classes: classesWithStudents,
          totalStudents,
          paidStudents,
        });
      }
    });

    return teachersWithClasses;
  };

  const handleTeacherToggle = (teacherId: string) => {
    const newExpanded = new Set(expandedTeachers);
    if (newExpanded.has(teacherId)) {
      newExpanded.delete(teacherId);
    } else {
      newExpanded.add(teacherId);
    }
    setExpandedTeachers(newExpanded);
  };

  const handleClassToggle = (classId: string) => {
    const newExpanded = new Set(expandedClasses);
    if (newExpanded.has(classId)) {
      newExpanded.delete(classId);
    } else {
      newExpanded.add(classId);
    }
    setExpandedClasses(newExpanded);
  };

  const handlePaymentClick = (student: StudentWithPaymentStatus) => {
    setPaymentAmount(student.tuition.toString());
    setPaymentDialog({
      isOpen: true,
      student,
      enrollment: student.enrollment,
    });
  };

  const handlePaymentSubmit = () => {
    if (!paymentDialog.enrollment || !paymentAmount) return;

    addPaymentMutation.mutate({
      enrollmentId: paymentDialog.enrollment.id,
      amount: parseInt(paymentAmount),
      paidDate: paymentDate,
    });
  };

  const formatAmount = (amount: number) => {
    return `₩${amount.toLocaleString()}`;
  };

  if (teachersLoading || classesLoading || studentsLoading || enrollmentsLoading || paymentsLoading) {
    return (
      <div className="space-y-6 p-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold">수납 관리</h1>
        </div>
        <div className="text-center py-8">
          <div className="text-muted-foreground">데이터를 불러오는 중...</div>
        </div>
      </div>
    );
  }

  const teacherData = processTeacherData();
  const currentMonth = new Date().toLocaleDateString('ko-KR', { year: 'numeric', month: 'long' });

  // 총수납액과 총미납액 계산
  const calculateFinancials = () => {
    const currentMonthString = new Date().toISOString().slice(0, 7); // YYYY-MM

    // 총수납액: 현재 달의 모든 payment 금액 합산
    const totalRevenue = payments
      .filter(p => p.paymentMonth === currentMonthString)
      .reduce((sum, p) => sum + (p.amount || 0), 0);

    // 총미납액: 미납 학생들의 수강료 합산
    const totalOutstanding = teacherData.reduce((total, teacher) => {
      return total + teacher.classes.reduce((classTotal, classItem) => {
        return classTotal + classItem.students
          .filter(student => !student.isPaid)
          .reduce((studentTotal, student) => studentTotal + (student.tuition || 0), 0);
      }, 0);
    }, 0);

    return { totalRevenue, totalOutstanding };
  };

  const { totalRevenue, totalOutstanding } = calculateFinancials();

  return (
    <div className="space-y-6 p-6" data-testid="payments-page">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">수납 관리</h1>
          <p className="text-muted-foreground">
            {currentMonth} 수납 현황
          </p>
        </div>
      </div>

      {/* Teacher-Class-Student hierarchy layout */}
      {teacherData.length === 0 ? (
        <div className="text-center py-12 border-2 border-dashed border-muted-foreground/25 rounded-lg">
          <User className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
          <div className="text-lg font-medium">등록된 선생님이 없습니다</div>
          <p className="text-muted-foreground mt-2">선생님을 먼저 등록하고 수업을 개설해주세요.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {teacherData.map((teacher: TeacherWithClasses) => {
            const isTeacherExpanded = expandedTeachers.has(teacher.id);

            return (
              <Card key={teacher.id} className="overflow-hidden">
                {/* Teacher Header */}
                <CardHeader 
                  className="hover-elevate cursor-pointer bg-primary/5"
                  onClick={() => handleTeacherToggle(teacher.id)}
                  data-testid={`teacher-header-${teacher.id}`}
                >
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      {isTeacherExpanded ? (
                        <ChevronDown className="h-5 w-5 text-muted-foreground" />
                      ) : (
                        <ChevronRight className="h-5 w-5 text-muted-foreground" />
                      )}
                      <div>
                        <CardTitle className="flex items-center gap-2">
                          <User className="h-5 w-5" />
                          {teacher.name} 선생님
                        </CardTitle>
                        <div className="text-sm text-muted-foreground mt-1">
                          {teacher.subject} • {teacher.classes.length}개 반
                        </div>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <Badge 
                        variant={teacher.paidStudents === teacher.totalStudents ? "default" : "secondary"}
                        className="px-3"
                      >
                        {teacher.paidStudents}/{teacher.totalStudents} 납부완료
                      </Badge>
                      <div className="text-right">
                        <div className="text-sm text-muted-foreground">수납률</div>
                        <div className="text-lg font-semibold">
                          {teacher.totalStudents > 0 ? Math.round((teacher.paidStudents / teacher.totalStudents) * 100) : 0}%
                        </div>
                      </div>
                    </div>
                  </div>
                </CardHeader>

                {/* Teacher's Classes */}
                {isTeacherExpanded && (
                  <CardContent className="pt-0 space-y-3">
                    {teacher.classes.map((classItem: ClassWithStudents) => {
                      const isExpanded = expandedClasses.has(classItem.id);
                      const paidCount = classItem.students.filter((s: StudentWithPaymentStatus) => s.isPaid).length;
                      const totalCount = classItem.students.length;

                      return (
                        <div key={classItem.id} className="border rounded-md overflow-hidden">
                          {/* Class Header */}
                          <div 
                            className="flex items-center justify-between p-3 cursor-pointer hover-elevate bg-muted/50"
                            onClick={() => handleClassToggle(classItem.id)}
                            data-testid={`class-header-${classItem.id}`}
                          >
                            <div className="flex items-center gap-2">
                              {isExpanded ? (
                                <ChevronDown className="h-5 w-5 text-muted-foreground" />
                              ) : (
                                <ChevronRight className="h-5 w-5 text-muted-foreground" />
                              )}
                              <div>
                                <div className="font-medium flex items-center gap-2">
                                  <BookOpen className="h-4 w-4" />
                                  {classItem.name}
                                </div>
                                {classItem.schedule && (
                                  <div className="text-sm text-muted-foreground mt-1">
                                    {classItem.schedule}
                                  </div>
                                )}
                              </div>
                            </div>
                            <div className="flex items-center gap-2">
                              <Badge 
                                variant={paidCount === totalCount ? "default" : "secondary"}
                                className="text-xs"
                              >
                                {paidCount}/{totalCount}
                              </Badge>
                              <div className="text-sm font-medium">
                                {totalCount > 0 ? Math.round((paidCount / totalCount) * 100) : 0}%
                              </div>
                            </div>
                          </div>

                          {/* Students */}
                          {isExpanded && (
                            <div className="p-2 space-y-2">
                              {classItem.students.map((student: StudentWithPaymentStatus) => (
                                <div 
                                  key={student.id}
                                  className="flex items-center justify-between p-3 bg-background rounded-lg hover-elevate"
                                  data-testid={`student-row-${student.id}`}
                                >
                                  <div className="flex items-center gap-3">
                                    <div className="flex items-center gap-2">
                                      {student.isPaid ? (
                                        <CheckCircle className="h-5 w-5 text-green-600" />
                                      ) : (
                                        <XCircle className="h-5 w-5 text-red-600" />
                                      )}
                                      <span className="font-medium">{student.name}</span>
                                      {student.grade && (
                                        <Badge variant="outline" className="text-xs">
                                          {student.grade}
                                        </Badge>
                                      )}
                                    </div>
                                  </div>

                                  <div className="flex items-center gap-3">
                                    <div className="text-right">
                                      <div className="font-medium">{formatAmount(student.tuition)}</div>
                                      {student.isPaid && student.latestPayment ? (
                                        <div className="text-xs text-green-600">
                                          {new Date(student.latestPayment.paidDate).toLocaleDateString()} 납부
                                        </div>
                                      ) : (
                                        <div className="text-xs text-red-600">미납</div>
                                      )}
                                    </div>

                                    {!student.isPaid && (userRole === 'owner' || userRole === 'teacher') ? (
                                      <Button 
                                        size="sm"
                                        onClick={() => handlePaymentClick(student)}
                                        data-testid={`payment-button-${student.id}`}
                                        variant="default"
                                      >
                                        <CreditCard className="h-4 w-4 mr-1" />
                                        납부하기
                                      </Button>
                                    ) : student.isPaid ? (
                                      <Badge variant="default" className="bg-green-100 text-green-800">
                                        납부완료
                                      </Badge>
                                    ) : (
                                      <Badge variant="secondary">
                                        미납
                                      </Badge>
                                    )}
                                  </div>
                                </div>
                              ))}
                            </div>
                          )}
                        </div>
                      );
                    })}
                  </CardContent>
                )}
              </Card>
            );
          })}
        </div>
      )}

      {/* Payment Dialog */}
      <Dialog open={paymentDialog.isOpen} onOpenChange={(open) => setPaymentDialog({ isOpen: open })}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>수납 등록</DialogTitle>
            <DialogDescription>
              {paymentDialog.student?.name} 학생의 {currentMonth} 수납을 등록합니다.
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-4">
            <div>
              <Label htmlFor="amount">수납 금액</Label>
              <Input
                id="amount"
                type="number"
                value={paymentAmount}
                onChange={(e) => setPaymentAmount(e.target.value)}
                placeholder="수납 금액을 입력하세요"
                data-testid="input-payment-amount"
              />
            </div>

            <div>
              <Label htmlFor="paidDate">납입 일자</Label>
              <Input
                id="paidDate"
                type="date"
                value={paymentDate}
                onChange={(e) => setPaymentDate(e.target.value)}
                data-testid="input-payment-date"
              />
            </div>
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setPaymentDialog({ isOpen: false })}
            >
              취소
            </Button>
            <Button 
              onClick={handlePaymentSubmit}
              disabled={addPaymentMutation.isPending || !paymentAmount}
              data-testid="button-submit-payment"
            >
              {addPaymentMutation.isPending ? "처리 중..." : "납부 완료"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* Summary */}
      {teacherData.length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <Calendar className="h-5 w-5" />
              {currentMonth} 수납 요약
            </CardTitle>
          </CardHeader>
          <CardContent className={`grid gap-4 ${userRole === 'owner' || userRole === 'superadmin' ? 'md:grid-cols-5' : 'md:grid-cols-4'}`}>
            <div className="text-center">
              <div className="text-2xl font-bold text-primary">
                {teacherData.reduce((sum: number, t: TeacherWithClasses) => sum + t.classes.length, 0)}개
              </div>
              <p className="text-sm text-muted-foreground">운영 반</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-green-600">
                {teacherData.reduce((sum: number, t: TeacherWithClasses) => sum + t.paidStudents, 0)}명
              </div>
              <p className="text-sm text-muted-foreground">납부 완료</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-red-600">
                {teacherData.reduce((sum: number, t: TeacherWithClasses) => sum + (t.totalStudents - t.paidStudents), 0)}명
              </div>
              <p className="text-sm text-muted-foreground">미납</p>
            </div>
            {/* 총수납액 - 원장만 */}
            {(userRole === 'owner' || userRole === 'superadmin') && (
              <div className="text-center">
                <div className="text-2xl font-bold text-blue-600">
                  ₩{totalRevenue.toLocaleString()}
                </div>
                <p className="text-sm text-muted-foreground">총수납액</p>
              </div>
            )}
            {/* 총미납액 - 원장과 교사 */}
            <div className="text-center">
              <div className="text-2xl font-bold text-orange-600">
                ₩{totalOutstanding.toLocaleString()}
              </div>
              <p className="text-sm text-muted-foreground">총미납액</p>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

client/src/pages/LessonLogs.tsx.content:
import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Plus, BookOpen, Calendar, FileText, GraduationCap, User, Info, Pencil } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { LessonLog, Class, User as UserType } from "@shared/schema";

const lessonLogFormSchema = z.object({
  classId: z.string().min(1, "반을 선택해주세요"),
  date: z.string().min(1, "수업 일자를 입력해주세요"),
  progress: z.string().optional(),
  homework: z.string().optional(), 
  notes: z.string().optional(),
});

type LessonLogFormData = z.infer<typeof lessonLogFormSchema>;

interface LessonLogsProps {
  userRole: 'owner' | 'teacher' | 'superadmin';
}

export default function LessonLogs({ userRole }: LessonLogsProps) {
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');
  const { toast } = useToast();

  // Fetch lesson logs
  const { data: lessonLogs = [], isLoading: lessonLogsLoading } = useQuery<LessonLog[]>({
    queryKey: ['/api/lesson-logs'],
  });

  // Fetch classes for dropdown and display
  const { data: classes = [], isLoading: classesLoading } = useQuery<Class[]>({
    queryKey: ['/api/classes'],
  });

  // Fetch users to map createdBy
  const { data: users = [] } = useQuery<UserType[]>({
    queryKey: ['/api/users'],
  });

  // Add lesson log mutation
  const addLessonLogMutation = useMutation({
    mutationFn: async (data: LessonLogFormData) => {
      const payload = {
        ...data,
        date: new Date(data.date),
      };
      const response = await apiRequest('POST', '/api/lesson-logs', payload);
      return await response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/lesson-logs'] });
      setIsAddDialogOpen(false);
      addForm.reset();
      toast({
        title: "수업 일지 등록 완료",
        description: "새 수업 일지가 성공적으로 등록되었습니다.",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "수업 일지 등록 실패",
        description: error.message || "수업 일지 등록 중 오류가 발생했습니다.",
        variant: "destructive",
      });
    },
  });

  // Form for adding lesson log
  const addForm = useForm<LessonLogFormData>({
    resolver: zodResolver(lessonLogFormSchema),
    defaultValues: {
      classId: "",
      date: new Date().toISOString().slice(0, 10), // YYYY-MM-DD
      progress: "",
      homework: "",
      notes: "",
    },
  });

  const handleAddLessonLog = (data: LessonLogFormData) => {
    addLessonLogMutation.mutate(data);
  };

  const getClassName = (classId: string) => {
    const classItem = classes.find(c => c.id === classId);
    return classItem?.name || "반 정보 없음";
  };

  const getCreatorName = (createdBy: string) => {
    const user = users.find(u => u.id === createdBy);
    return user?.name || "사용자 정보 없음";
  };

  const getFilteredLessonLogs = () => {
    if (selectedClassFilter === 'all') return lessonLogs;
    return lessonLogs.filter(log => log.classId === selectedClassFilter);
  };

  const formatDate = (dateString: string | Date) => {
    const date = dateString instanceof Date ? dateString : new Date(dateString);
    return date.toLocaleDateString('ko-KR', {
      year: 'numeric',
      month: 'long', 
      day: 'numeric',
      weekday: 'short'
    });
  };

  if (lessonLogsLoading || classesLoading) {
    return (
      <div className="space-y-6 p-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold">반별 일지</h1>
        </div>
        <div className="text-center py-8">
          <div className="text-muted-foreground">반별 일지를 불러오는 중...</div>
        </div>
      </div>
    );
  }

  const filteredLogs = getFilteredLessonLogs();

  return (
    <div className="space-y-6 p-6" data-testid="lesson-logs-page">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">반별 일지</h1>
          <p className="text-muted-foreground">
            수업 일지 {filteredLogs.length}건이 등록되어 있습니다
          </p>
        </div>

        {(userRole === 'owner' || userRole === 'teacher') && (
          <Dialog open={isAddDialogOpen} onOpenChange={setIsAddDialogOpen}>
            <DialogTrigger asChild>
              <Button data-testid="button-add-lesson-log">
                <Plus className="h-4 w-4 mr-2" />
                일지 작성
              </Button>
            </DialogTrigger>
            <DialogContent className="max-w-lg">
              <DialogHeader>
                <DialogTitle>새 수업 일지 작성</DialogTitle>
                <DialogDescription>
                  수업 일지 정보를 입력해주세요.
                </DialogDescription>
              </DialogHeader>
              <Form {...addForm}>
                <form onSubmit={addForm.handleSubmit(handleAddLessonLog)} className="space-y-4">
                  <FormField
                    control={addForm.control}
                    name="classId"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>반 선택</FormLabel>
                        <Select onValueChange={field.onChange} value={field.value}>
                          <FormControl>
                            <SelectTrigger data-testid="select-class">
                              <SelectValue placeholder="반을 선택하세요" />
                            </SelectTrigger>
                          </FormControl>
                          <SelectContent>
                            {classes.filter(c => c.isActive !== false).map((classItem) => (
                              <SelectItem key={classItem.id} value={classItem.id}>
                                {classItem.name}
                              </SelectItem>
                            ))}
                          </SelectContent>
                        </Select>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={addForm.control}
                    name="date"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>수업 일자</FormLabel>
                        <FormControl>
                          <Input 
                            type="date"
                            data-testid="input-lesson-date"
                            {...field}
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={addForm.control}
                    name="progress"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>진도 사항</FormLabel>
                        <FormControl>
                          <Textarea 
                            placeholder="오늘 진행한 수업 내용과 진도를 입력하세요" 
                            rows={3}
                            data-testid="input-lesson-progress"
                            {...field} 
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={addForm.control}
                    name="homework"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>숙제</FormLabel>
                        <FormControl>
                          <Textarea 
                            placeholder="학생들에게 내준 숙제를 입력하세요" 
                            rows={2}
                            data-testid="input-lesson-homework"
                            {...field} 
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <FormField
                    control={addForm.control}
                    name="notes"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>특이사항</FormLabel>
                        <FormControl>
                          <Textarea 
                            placeholder="수업 중 특별한 사항이나 메모를 입력하세요" 
                            rows={2}
                            data-testid="input-lesson-notes"
                            {...field} 
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <DialogFooter>
                    <Button 
                      type="submit" 
                      disabled={addLessonLogMutation.isPending}
                      data-testid="button-submit-add-lesson-log"
                    >
                      {addLessonLogMutation.isPending ? "등록 중..." : "등록"}
                    </Button>
                  </DialogFooter>
                </form>
              </Form>
            </DialogContent>
          </Dialog>
        )}

        {userRole === 'superadmin' && (
          <div className="text-sm text-muted-foreground bg-muted/50 px-3 py-2 rounded-lg flex items-center gap-2">
            <Info className="h-4 w-4" />
            <span>수업 일지 작성은 학원장과 교사만 가능합니다</span>
          </div>
        )}
      </div>

      {/* Filter Controls */}
      <div className="flex items-center gap-4">
        <div className="flex items-center gap-2">
          <Label htmlFor="class-filter">반별 필터:</Label>
          <Select value={selectedClassFilter} onValueChange={setSelectedClassFilter}>
            <SelectTrigger className="w-48" data-testid="select-class-filter">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">전체 반</SelectItem>
              {classes.filter(c => c.isActive !== false).map((classItem) => (
                <SelectItem key={classItem.id} value={classItem.id}>
                  {classItem.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <Badge variant="secondary" data-testid="filtered-count">
          {filteredLogs.length}건
        </Badge>
      </div>

      {/* Lesson Logs Grid */}
      {filteredLogs.length === 0 ? (
        <div className="text-center py-12 border-2 border-dashed border-muted-foreground/25 rounded-lg">
          <Pencil className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
          <div className="text-lg font-medium">
            {selectedClassFilter === 'all' ? '등록된 수업 일지가 없습니다' : '해당 반의 수업 일지가 없습니다'}
          </div>
          <p className="text-muted-foreground mt-2">첫 번째 수업 일지를 작성해보세요.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {/* Sort by date descending */}
          {[...filteredLogs]
            .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
            .map((log) => (
            <Card key={log.id} className="hover-elevate" data-testid={`lesson-log-card-${log.id}`}>
              <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-3">
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <CardTitle className="text-lg" data-testid={`lesson-log-class-${log.id}`}>
                      {getClassName(log.classId)}
                    </CardTitle>
                    <Badge variant="outline" data-testid={`lesson-log-date-${log.id}`}>
                      <Calendar className="h-3 w-3 mr-1" />
                      {formatDate(log.date)}
                    </Badge>
                  </div>
                  <div className="flex items-center gap-2 text-sm text-muted-foreground">
                    <User className="h-4 w-4" />
                    <span data-testid={`lesson-log-creator-${log.id}`}>
                      작성: {getCreatorName(log.createdBy)}
                    </span>
                  </div>
                </div>
              </CardHeader>
              <CardContent className="space-y-3">
                {log.progress && (
                  <div className="space-y-1">
                    <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                      <BookOpen className="h-4 w-4" />
                      진도 사항
                    </div>
                    <div className="pl-6 text-sm" data-testid={`lesson-log-progress-${log.id}`}>
                      {log.progress}
                    </div>
                  </div>
                )}
                {log.homework && (
                  <div className="space-y-1">
                    <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                      <GraduationCap className="h-4 w-4" />
                      숙제
                    </div>
                    <div className="pl-6 text-sm" data-testid={`lesson-log-homework-${log.id}`}>
                      {log.homework}
                    </div>
                  </div>
                )}
                {log.notes && (
                  <div className="space-y-1">
                    <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                      <FileText className="h-4 w-4" />
                      특이사항
                    </div>
                    <div className="pl-6 text-sm" data-testid={`lesson-log-notes-${log.id}`}>
                      {log.notes}
                    </div>
                  </div>
                )}
                <div className="text-xs text-muted-foreground pt-2 border-t">
                  등록일: {new Date(log.createdAt).toLocaleDateString('ko-KR')} {new Date(log.createdAt).toLocaleTimeString('ko-KR', { hour: '2-digit', minute: '2-digit' })}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Summary Stats */}
      {lessonLogs.length > 0 && (
        <Card className="mt-6">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <BookOpen className="h-5 w-5" />
              수업 일지 요약
            </CardTitle>
          </CardHeader>
          <CardContent className="grid gap-4 md:grid-cols-3">
            <div className="text-center">
              <div className="text-2xl font-bold text-primary">
                {lessonLogs.length}건
              </div>
              <p className="text-sm text-muted-foreground">총 일지 수</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-green-600">
                {classes.filter(c => c.isActive !== false).length}개
              </div>
              <p className="text-sm text-muted-foreground">활성 반</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-blue-600">
                {filteredLogs.length}건
              </div>
              <p className="text-sm text-muted-foreground">현재 필터 결과</p>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

client/src/pages/Overdues.tsx.content:
import { useState, useMemo } from "react";
import { useQuery } from "@tanstack/react-query";
import { AlertTriangle, Phone, Mail, Calendar, DollarSign, User, BookOpen, Filter } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Payment, Enrollment, Student, Class } from "@shared/schema";

interface OverdueInfo {
  enrollment: Enrollment;
  student: Student;
  class: Class;
  overdueMonths: string[];
  totalOverdueAmount: number;
  latestOverdueMonth: string;
}

interface OverduesProps {
  userRole: 'owner' | 'teacher' | 'superadmin';
}

export default function Overdues({ userRole }: OverduesProps) {
  const [selectedClassFilter, setSelectedClassFilter] = useState<string>('all');
  const [overdueSeverity, setOverdueSeverity] = useState<string>('all'); // all, recent, severe

  // Fetch all required data
  const { data: payments = [], isLoading: paymentsLoading, isError: paymentsError } = useQuery<Payment[]>({
    queryKey: ['/api/payments'],
  });

  const { data: enrollments = [], isLoading: enrollmentsLoading, isError: enrollmentsError } = useQuery<Enrollment[]>({
    queryKey: ['/api/enrollments'],
  });

  const { data: students = [], isLoading: studentsLoading, isError: studentsError } = useQuery<Student[]>({
    queryKey: ['/api/students'],
  });

  const { data: classes = [], isLoading: classesLoading, isError: classesError } = useQuery<Class[]>({
    queryKey: ['/api/classes'],
  });

  // Calculate overdue information
  const overdueList = useMemo((): OverdueInfo[] => {
    if (!enrollments.length || !students.length || !classes.length) {
      return [];
    }

    const currentDate = new Date();
    const currentYear = currentDate.getFullYear();
    const currentMonth = currentDate.getMonth() + 1; // getMonth() returns 0-11

    const overdues: OverdueInfo[] = [];

    // Check each active enrollment
    enrollments
      .filter(enrollment => enrollment.isActive)
      .forEach(enrollment => {
        const student = students.find(s => s.id === enrollment.studentId);
        const classItem = classes.find(c => c.id === enrollment.classId);

        if (!student || !classItem) return;

        const startDate = new Date(enrollment.startDate);
        const endDate = enrollment.endDate ? new Date(enrollment.endDate) : currentDate;
        const dueDay = enrollment.dueDay || 8;

        const overdueMonths: string[] = [];
        let totalOverdueAmount = 0;
        const tuitionAmount = enrollment.tuition || classItem.defaultTuition || 0;

        // Check each month from start date to current/end date
        let checkDate = new Date(startDate.getFullYear(), startDate.getMonth(), 1);

        while (checkDate <= endDate && checkDate <= currentDate) {
          const checkYear = checkDate.getFullYear();
          const checkMonth = checkDate.getMonth() + 1;
          const paymentMonth = `${checkYear}-${checkMonth.toString().padStart(2, '0')}`;

          // Check if due date has passed
          const dueDate = new Date(checkYear, checkMonth - 1, dueDay);
          if (currentDate > dueDate) {
            // Look for payment for this month
            const hasPayment = payments.some(payment => 
              payment.enrollmentId === enrollment.id && 
              payment.paymentMonth === paymentMonth
            );

            if (!hasPayment) {
              overdueMonths.push(paymentMonth);
              totalOverdueAmount += tuitionAmount;
            }
          }

          // Move to next month
          checkDate.setMonth(checkDate.getMonth() + 1);
        }

        if (overdueMonths.length > 0) {
          overdues.push({
            enrollment,
            student,
            class: classItem,
            overdueMonths,
            totalOverdueAmount,
            latestOverdueMonth: overdueMonths[overdueMonths.length - 1],
          });
        }
      });

    return overdues;
  }, [enrollments, payments, students, classes]);

  // Filter overdue list
  const filteredOverdues = useMemo(() => {
    let filtered = overdueList;

    // Filter by class
    if (selectedClassFilter !== 'all') {
      filtered = filtered.filter(overdue => overdue.class.id === selectedClassFilter);
    }

    // Filter by severity
    if (overdueSeverity === 'recent') {
      // Only 1 month overdue
      filtered = filtered.filter(overdue => overdue.overdueMonths.length === 1);
    } else if (overdueSeverity === 'severe') {
      // 2 or more months overdue
      filtered = filtered.filter(overdue => overdue.overdueMonths.length >= 2);
    }

    // Sort by total overdue amount (descending)
    return [...filtered].sort((a, b) => b.totalOverdueAmount - a.totalOverdueAmount);
  }, [overdueList, selectedClassFilter, overdueSeverity]);

  const formatAmount = (amount: number) => {
    return `₩${amount.toLocaleString()}`;
  };

  const formatOverdueMonths = (months: string[]) => {
    return months.map(month => {
      const [year, monthStr] = month.split('-');
      return `${year}.${monthStr}`;
    }).join(', ');
  };

  const getSeverityBadge = (monthsCount: number) => {
    if (monthsCount === 1) {
      return <Badge variant="secondary">1개월</Badge>;
    } else if (monthsCount >= 2 && monthsCount < 4) {
      return <Badge variant="destructive">위험 {monthsCount}개월</Badge>;
    } else {
      return <Badge variant="destructive">심각 {monthsCount}개월</Badge>;
    }
  };

  // Handle errors
  const hasErrors = paymentsError || enrollmentsError || studentsError || classesError;
  const isLoading = paymentsLoading || enrollmentsLoading || studentsLoading || classesLoading;

  if (isLoading) {
    return (
      <div className="space-y-6 p-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold">미납 알림</h1>
        </div>
        <div className="text-center py-8">
          <div className="text-muted-foreground">미납 정보를 분석하는 중...</div>
        </div>
      </div>
    );
  }

  if (hasErrors) {
    return (
      <div className="space-y-6 p-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold">미납 알림</h1>
        </div>
        <Alert className="border-red-200 bg-red-50 dark:bg-red-900/20">
          <AlertTriangle className="h-4 w-4" />
          <AlertTitle>데이터 로딩 오류</AlertTitle>
          <AlertDescription>
            미납 정보를 불러오는 중 오류가 발생했습니다. 페이지를 새로고침해 주세요.
          </AlertDescription>
        </Alert>
      </div>
    );
  }

  return (
    <div className="space-y-6 p-6" data-testid="overdues-page">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">미납 알림</h1>
          <p className="text-muted-foreground">
            {filteredOverdues.length}명의 미납자가 있습니다
          </p>
        </div>
      </div>

      {/* Alert Summary */}
      {overdueList.length > 0 && (
        <Alert className="border-orange-200 bg-orange-50 dark:bg-orange-900/20">
          <AlertTriangle className="h-4 w-4" />
          <AlertTitle>미납 현황 알림</AlertTitle>
          <AlertDescription>
            총 {overdueList.length}명의 학생에게 미납이 있으며, 
            총 미납액은 {formatAmount(overdueList.reduce((sum, item) => sum + item.totalOverdueAmount, 0))}입니다.
          </AlertDescription>
        </Alert>
      )}

      {/* Filter Controls */}
      <div className="flex items-center gap-4 flex-wrap">
        <div className="flex items-center gap-2">
          <Label htmlFor="class-filter">반별 필터:</Label>
          <Select value={selectedClassFilter} onValueChange={setSelectedClassFilter}>
            <SelectTrigger className="w-48" data-testid="select-class-filter">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">전체 반</SelectItem>
              {classes.filter(c => c.isActive !== false).map((classItem) => (
                <SelectItem key={classItem.id} value={classItem.id}>
                  {classItem.name}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        <div className="flex items-center gap-2">
          <Label htmlFor="severity-filter">심각도:</Label>
          <Select value={overdueSeverity} onValueChange={setOverdueSeverity}>
            <SelectTrigger className="w-40" data-testid="select-severity-filter">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="all">전체</SelectItem>
              <SelectItem value="recent">최근 (1개월)</SelectItem>
              <SelectItem value="severe">심각 (2개월+)</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <Badge variant="outline" data-testid="filtered-count">
          <Filter className="h-3 w-3 mr-1" />
          {filteredOverdues.length}명
        </Badge>
      </div>

      {/* Overdue List */}
      {filteredOverdues.length === 0 ? (
        <div className="text-center py-12 border-2 border-dashed border-muted-foreground/25 rounded-lg">
          {overdueList.length === 0 ? (
            <>
              <DollarSign className="h-12 w-12 mx-auto text-green-500 mb-4" />
              <div className="text-lg font-medium text-green-600">미납자가 없습니다</div>
              <p className="text-muted-foreground mt-2">모든 학생이 정상적으로 납부했습니다.</p>
            </>
          ) : (
            <>
              <Filter className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
              <div className="text-lg font-medium">필터 조건에 해당하는 미납자가 없습니다</div>
              <p className="text-muted-foreground mt-2">다른 필터 조건을 시도해보세요.</p>
            </>
          )}
        </div>
      ) : (
        <div className="space-y-4">
          {filteredOverdues.map((overdue) => (
            <Card key={overdue.enrollment.id} className="hover-elevate" data-testid={`overdue-card-${overdue.enrollment.id}`}>
              <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-3">
                <div className="space-y-1">
                  <div className="flex items-center gap-2">
                    <CardTitle className="text-lg" data-testid={`overdue-student-${overdue.enrollment.id}`}>
                      {overdue.student.name}
                    </CardTitle>
                    {getSeverityBadge(overdue.overdueMonths.length)}
                  </div>
                  <div className="flex items-center gap-4 text-sm text-muted-foreground">
                    <div className="flex items-center gap-1">
                      <BookOpen className="h-4 w-4" />
                      <span data-testid={`overdue-class-${overdue.enrollment.id}`}>
                        {overdue.class.name}
                      </span>
                    </div>
                    {overdue.student.parentPhone && (
                      <div className="flex items-center gap-1">
                        <Phone className="h-4 w-4" />
                        <span data-testid={`overdue-phone-${overdue.enrollment.id}`}>
                          {overdue.student.parentPhone}
                        </span>
                      </div>
                    )}
                  </div>
                </div>
                <div className="text-right">
                  <div className="text-xl font-bold text-red-600" data-testid={`overdue-amount-${overdue.enrollment.id}`}>
                    {formatAmount(overdue.totalOverdueAmount)}
                  </div>
                  <div className="text-sm text-muted-foreground">
                    {overdue.overdueMonths.length}개월 미납
                  </div>
                </div>
              </CardHeader>
              <CardContent className="space-y-3">
                <div className="space-y-1">
                  <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                    <Calendar className="h-4 w-4" />
                    미납 월
                  </div>
                  <div className="pl-6 text-sm" data-testid={`overdue-months-${overdue.enrollment.id}`}>
                    {formatOverdueMonths(overdue.overdueMonths)}
                  </div>
                </div>

                <div className="space-y-1">
                  <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                    <DollarSign className="h-4 w-4" />
                    월 수강료
                  </div>
                  <div className="pl-6 text-sm">
                    {formatAmount(overdue.enrollment.tuition || overdue.class.defaultTuition || 0)}
                  </div>
                </div>

                {overdue.student.school && (
                  <div className="space-y-1">
                    <div className="flex items-center gap-2 text-sm font-medium text-muted-foreground">
                      <User className="h-4 w-4" />
                      학생 정보
                    </div>
                    <div className="pl-6 text-sm">
                      {overdue.student.school} {overdue.student.grade && `${overdue.student.grade}`}
                    </div>
                  </div>
                )}

                {(userRole === 'owner' || userRole === 'teacher') && (
                  <div className="flex gap-2 pt-3 border-t">
                    <Button 
                      size="sm" 
                      variant="outline"
                      data-testid={`button-call-${overdue.enrollment.id}`}
                      disabled={!overdue.student.parentPhone}
                    >
                      <Phone className="h-4 w-4 mr-2" />
                      전화하기
                    </Button>
                    <Button 
                      size="sm" 
                      variant="outline"
                      data-testid={`button-sms-${overdue.enrollment.id}`}
                      disabled={!overdue.student.parentPhone}
                    >
                      <Mail className="h-4 w-4 mr-2" />
                      알림 발송
                    </Button>
                  </div>
                )}
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Summary Stats */}
      {overdueList.length > 0 && (
        <Card className="mt-6">
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <AlertTriangle className="h-5 w-5" />
              미납 요약 통계
            </CardTitle>
          </CardHeader>
          <CardContent className="grid gap-4 md:grid-cols-4">
            <div className="text-center">
              <div className="text-2xl font-bold text-red-600">
                {overdueList.length}명
              </div>
              <p className="text-sm text-muted-foreground">전체 미납자</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-orange-600">
                {overdueList.filter(item => item.overdueMonths.length === 1).length}명
              </div>
              <p className="text-sm text-muted-foreground">최근 미납 (1개월)</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-red-700">
                {overdueList.filter(item => item.overdueMonths.length >= 2).length}명
              </div>
              <p className="text-sm text-muted-foreground">심각 미납 (2개월+)</p>
            </div>
            <div className="text-center">
              <div className="text-2xl font-bold text-red-600">
                {formatAmount(overdueList.reduce((sum, item) => sum + item.totalOverdueAmount, 0))}
              </div>
              <p className="text-sm text-muted-foreground">총 미납액</p>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

